input.content:
:root {
  --bg: #0b1120;
  --panel: #111a2e;
  --panel-2: #0e1626;
  --border: #1e293b;
  --text: #e2e8f0;
  --muted: #94a3b8;
  --accent: #6366f1;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: radial-gradient(1200px 600px at 70% -10%, #16223e 0%, var(--bg) 55%);
  color: var(--text);
  font-family: "Inter", -apple-system, "PingFang SC", "Microsoft YaHei", system-ui, sans-serif;
  font-size: 14px;
  line-height: 1.6;
}

.app {
  max-width: 1280px;
  margin: 0 auto;
  padding: 28px 22px 60px;
}

.hero h1 {
  margin: 0;
  font-size: 30px;
  font-weight: 800;
  letter-spacing: 0.5px;
  background: linear-gradient(90deg, #818cf8, #22d3ee);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}
.hero .sub {
  color: var(--muted);
  margin: 6px 0 22px;
}
.hero .tag {
  display: inline-block;
  margin-left: 12px;
  font-size: 12px;
  color: #67e8f9;
  background: #0e749022;
  border: 1px solid #155e7544;
  padding: 2px 10px;
  border-radius: 20px;
}

.layout {
  display: grid;
  grid-template-columns: 400px 1fr;
  gap: 20px;
  align-items: start;
}
@media (max-width: 920px) {
  .layout {
    grid-template-columns: 1fr;
  }
}

.card,
.trace,
.claim-card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 16px;
  margin-bottom: 16px;
}

.left {
  position: sticky;
  top: 18px;
}

/* ---- input ---- */
.mode-tabs {
  display: flex;
  gap: 6px;
  margin-bottom: 12px;
}
.mode-tabs button {
  flex: 1;
  background: var(--panel-2);
  color: var(--muted);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 7px;
  cursor: pointer;
}
.mode-tabs button.active {
  background: var(--accent);
  color: #fff;
  border-color: var(--accent);
}
textarea,
.url-input {
  width: 100%;
  background: var(--panel-2);
  border: 1px solid var(--border);
